// psRowClass styles inactive rows.
func psRowClass(item models.ProductService) string {
	if !item.IsActive {
		return "border-b border-border-subtle bg-background text-text-muted2"
	}
	return "border-b border-border-subtle"
}

// psAccountLabel returns code · name for the revenue account, falling back to the ID.
func psAccountLabel(item models.ProductService) string {
	if item.RevenueAccount.Code != "" {
		return item.RevenueAccount.Code + " · " + item.RevenueAccount.Name
	}
	return Uitoa(item.RevenueAccountID)
}

